# .github/workflows/ownership-check.yml
name: Ownership Compliance Check
on:
  pull_request:
    types: [opened, synchronize, review_submitted]

jobs:
  check-ai-ownership:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - name: Check prompt changes have ML review
        uses: actions/github-script@v7
        with:
          script: |
            const { data: files } = await github.rest.pulls.listFiles({
              owner: context.repo.owner,
              repo: context.repo.repo,
              pull_number: context.issue.number,
            });

            const promptFiles = files.filter(f => f.filename.startsWith('prompts/'));
            if (promptFiles.length === 0) {
              console.log('No prompt files changed - check passed');
              return;
            }

            const { data: reviews } = await github.rest.pulls.listReviews({
              owner: context.repo.owner,
              repo: context.repo.repo,
              pull_number: context.issue.number,
            });

            const mlTeamMembers = ['alice', 'bob', 'carol']; // from team API
            const mlApproved = reviews.some(r => 
              r.state === 'APPROVED' && mlTeamMembers.includes(r.user.login)
            );

            if (!mlApproved) {
              core.setFailed(
                `PR changes ${promptFiles.length} prompt file(s) but has no ML team approval.` +
                ' Request review from @org/ml-team.'
              );
            }
